module RefModule(bin, gray);

    input [3:0] bin;
    output reg [3:0] gray;
  wire [3:0] _tap_bin = bin & {4{1'b1}};


    always @(*)
        begin
            gray[3] = bin[3];
            gray[2] = bin[3] ^ bin[2];
            gray[1] = bin[2] ^ bin[1];
            gray[0] = bin[1] ^ bin[0];
        end  

endmodule
